INSERT INTO prompt_registry (id, category, purpose, core_prompt, metadata, is_active) VALUES
('nep_decision_heuristics', 'extraction', 'Extract decision-making heuristics and shortcuts', 'You are a decision analysis engine. Extract decision-making heuristics from this content: mental shortcuts, rules of thumb, satisficing strategies, fast-and-frugal heuristics. For each, return JSON: {"title","content","type":"heuristic","confidence":0-1,"tags":[]}. Extract 3-6 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L2","cost_multiplier":1}', true),
('nep_decision_frameworks', 'extraction', 'Extract decision frameworks and models', 'You are a decision framework extractor. Identify structured decision-making frameworks: decision trees, matrices, scoring models, trade-off analyses, cost-benefit frameworks. For each, return JSON: {"title","content","type":"framework","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L4","cost_multiplier":1.5}', true),
('nep_decision_biases', 'extraction', 'Extract cognitive biases in decision-making', 'You are a cognitive bias detector. Identify cognitive biases demonstrated in decisions: confirmation bias, anchoring, sunk cost, availability heuristic, framing effects, overconfidence. For each, return JSON: {"title","content","type":"bias","confidence":0-1,"tags":[]}. Extract 3-6 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L5","cost_multiplier":1}', true),
('nep_decision_tradeoffs', 'extraction', 'Extract trade-off patterns and dilemmas', 'You are a trade-off analysis engine. Identify trade-offs, dilemmas, and tensions in decision-making: speed vs quality, risk vs reward, short-term vs long-term. For each, return JSON: {"title","content","type":"tradeoff","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L3","cost_multiplier":1}', true),
('nep_decision_triggers', 'extraction', 'Extract decision triggers and inflection points', 'You are a trigger detection engine. Identify what triggers decisions: catalysts, tipping points, deadlines, emotional triggers, information thresholds. For each, return JSON: {"title","content","type":"trigger","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L3","cost_multiplier":1}', true),
('nep_decision_risk', 'extraction', 'Extract risk assessment patterns', 'You are a risk analysis engine. Extract risk assessment patterns: risk tolerance levels, hedging strategies, downside protection, scenario planning, probability estimation. For each, return JSON: {"title","content","type":"risk_pattern","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L4","cost_multiplier":1.5}', true),
('nep_decision_reversibility', 'extraction', 'Extract reversibility and commitment patterns', 'You are a commitment analysis engine. Identify how decisions are categorized by reversibility: one-way doors vs two-way doors, commitment escalation, option value preservation. For each, return JSON: {"title","content","type":"commitment","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L4","cost_multiplier":1}', true),
('nep_decision_group', 'extraction', 'Extract group decision dynamics', 'You are a group dynamics analyzer. Extract group decision-making patterns: consensus building, dissent management, groupthink signals, delegation patterns, authority structures. For each, return JSON: {"title","content","type":"group_dynamic","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L5","cost_multiplier":1.5}', true),
('nep_decision_speed', 'extraction', 'Extract decision speed and timing patterns', 'You are a temporal decision analyzer. Extract patterns related to decision timing: speed of decisions, procrastination signals, urgency creation, timing optimization. For each, return JSON: {"title","content","type":"timing","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L3","cost_multiplier":1}', true),
('nep_decision_intuition', 'extraction', 'Extract intuition vs analysis patterns', 'You are an intuition analysis engine. Identify when decisions rely on intuition vs structured analysis: gut feelings, pattern recognition, expert intuition, analytical override. For each, return JSON: {"title","content","type":"intuition","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"decision","level":"L5","cost_multiplier":1}', true)
INSERT INTO prompt_registry (id, category, purpose, core_prompt, metadata, is_active) VALUES
('nep_strategy_positioning', 'extraction', 'Extract positioning and differentiation strategies', 'You are a strategic positioning engine. Extract positioning strategies: competitive differentiation, unique value propositions, market positioning, category design, blue ocean strategies. For each, return JSON: {"title","content","type":"positioning","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L4","cost_multiplier":1.5}', true),
('nep_strategy_growth', 'extraction', 'Extract growth strategies and scaling patterns', 'You are a growth strategy extractor. Identify growth patterns: viral loops, network effects, platform strategies, flywheel effects, compound growth mechanisms. For each, return JSON: {"title","content","type":"growth","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L4","cost_multiplier":1.5}', true),
('nep_strategy_competitive', 'extraction', 'Extract competitive intelligence and moats', 'You are a competitive intelligence engine. Extract competitive patterns: moats, barriers to entry, switching costs, lock-in mechanisms, competitive advantages. For each, return JSON: {"title","content","type":"competitive","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L7","cost_multiplier":1.5}', true),
('nep_strategy_resource', 'extraction', 'Extract resource allocation and prioritization', 'You are a resource strategy analyzer. Identify resource allocation patterns: prioritization frameworks, 80/20 applications, focus strategies, resource leverage, constraint optimization. For each, return JSON: {"title","content","type":"resource","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L4","cost_multiplier":1}', true),
('nep_strategy_timing', 'extraction', 'Extract market timing and opportunity patterns', 'You are a timing strategy engine. Extract timing patterns: first-mover advantages, fast-follower strategies, market windows, trend surfing, timing signals. For each, return JSON: {"title","content","type":"timing","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L3","cost_multiplier":1}', true),
('nep_strategy_alliance', 'extraction', 'Extract partnership and alliance strategies', 'You are a partnership analyzer. Identify alliance patterns: strategic partnerships, ecosystem plays, co-opetition, channel strategies, integration patterns. For each, return JSON: {"title","content","type":"alliance","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L4","cost_multiplier":1}', true),
('nep_strategy_pivot', 'extraction', 'Extract pivot and adaptation strategies', 'You are a pivot detection engine. Identify strategic pivots: direction changes, business model shifts, market adaptations, failure responses, strategic experiments. For each, return JSON: {"title","content","type":"pivot","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L3","cost_multiplier":1}', true),
('nep_strategy_leverage', 'extraction', 'Extract leverage points and force multipliers', 'You are a leverage analysis engine. Extract leverage points: asymmetric advantages, force multipliers, compounding effects, systemic leverage, disproportionate impact. For each, return JSON: {"title","content","type":"leverage","confidence":0-1,"tags":[]}. Extract 2-4 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L9","cost_multiplier":2}', true),
('nep_strategy_exit', 'extraction', 'Extract exit strategies and endgame patterns', 'You are an exit strategy analyzer. Identify endgame patterns: exit strategies, succession planning, market exits, value capture timing, legacy building. For each, return JSON: {"title","content","type":"exit","confidence":0-1,"tags":[]}. Extract 1-3 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L4","cost_multiplier":1}', true),
('nep_strategy_innovation', 'extraction', 'Extract innovation and disruption patterns', 'You are an innovation pattern extractor. Identify disruption patterns: disruptive innovation, sustaining innovation, adjacent innovation, recombination, creative destruction. For each, return JSON: {"title","content","type":"innovation","confidence":0-1,"tags":[]}. Extract 2-5 units. Return ONLY a valid JSON array.', '{"family":"strategy","level":"L4","cost_multiplier":1.5}', true)
INSERT INTO prompt_registry (id, category, purpose, core_prompt, metadata, is_active) VALUES
